// ============================================================
// DRIFT MANAGER — Step 1: Read all canon files + chapter
// Canon hierarchy: Series Bible > SSOT > Watcher Tech >
//                  Dossiers > Constitution > Chapter
// ============================================================
const fs = require('fs');

// --- Determine chapter from webhook body ---
const body = $input.first().json.body || $input.first().json;
const chapterInput = (body.chapter || 'CHAPTER_01').toUpperCase().replace('.MD','');
const chapterPath = `/data/TNC/MANUSCRIPT/book_2/CHAPTERS/${chapterInput}.md`;

// --- Safe file reader ---
const readFile = (path, label) => {
  try {
    const content = fs.readFileSync(path, 'utf8');
    return { content, found: true, label };
  } catch(e) {
    return { content: `[FILE NOT FOUND: ${path}]`, found: false, label };
  }
};

// --- Read all canon files (tiered token budgets) ---
const seriesBible    = readFile('/data/TNC/CANON/SERIES_BIBLE.md',                                         'SERIES_BIBLE');
const ssot           = readFile('/data/TNC/CANON/SSOT_v3_MASTER.md',                                       'SSOT_v3');
const watcherTech    = readFile('/data/TNC/CANON/WATCHER_TECHNOLOGY.md',                                    'WATCHER_TECHNOLOGY');
const constitution   = readFile('/data/TNC/MANUSCRIPT/book_2/ANALYSIS/CONSTITUTION.md',                     'CONSTITUTION_B2');
const protagonists   = readFile('/data/TNC/CANON/dossiers/PROTAGONIST_DOSSIERS.md',                         'PROTAGONIST_DOSSIERS');
const antagonists    = readFile('/data/TNC/CANON/dossiers/ANTAGONIST_DOSSIERS.md',                          'ANTAGONIST_DOSSIERS');
const watchers       = readFile('/data/TNC/CANON/dossiers/WATCHER_DOSSIERS.md',                             'WATCHER_DOSSIERS');
const nephilim       = readFile('/data/TNC/CANON/dossiers/NEPHILIM_DOSSIERS.md',                            'NEPHILIM_DOSSIERS');
const chapter        = readFile(chapterPath,                                                                 chapterInput);

// --- Warn if chapter not found ---
if (!chapter.found) {
  return [{ json: {
    error: true,
    message: `Chapter file not found: ${chapterPath}. Create the file first.`,
    chapter: chapterInput
  }}];
}

// --- Token budget per tier (chars — approx 4 chars/token, mistral 32k ctx)
// Total budget ~24,000 chars for canon, leaving room for chapter + prompt
const BUDGET = {
  seriesBible:  6000,   // Tier 1 — INVIOLABLE — highest priority
  ssot:         5000,   // Tier 2 — Master facts
  watcherTech:  2000,   // Tier 2a — Acoustic Paradigm
  constitution: 3000,   // Book 2 specific — critical for continuity
  protagonists: 2500,   // Character details
  antagonists:  2000,   // Antagonist details
  watchers:     1500,   // Watcher dossiers
  nephilim:     1000,   // Nephilim dossiers
  chapter:      15000   // The actual chapter — needs full read
};

const trim = (text, limit) => text.length > limit ? text.substring(0, limit) + '\n...[TRUNCATED — see full file]' : text;

// --- Build master prompt ---
const today = new Date().toISOString().split('T')[0];

const prompt = `You are the DRIFT MANAGER for The Nephilim Chronicles Book 2 by Kerman Gild.

YOUR SINGLE JOB: Identify every continuity, theological, or character drift issue in the chapter below.
Cross-reference against ALL canon documents provided in order of authority.

====================================================================
SEVERITY GUIDE:
  HIGH   = Theological contradiction, major plot inconsistency, character identity error
  MED    = Character voice drift, timeline error, Acoustic Paradigm violation, pacing/logic issue
  LOW    = Minor factual inconsistency, style drift, anachronism
====================================================================

CRITICAL DRIFT RULES — CHECK EVERY CHAPTER:
  1. Azazel = NEPHILIM (son of Gadreel the Watcher) — NOT a Watcher himself [HIGH if wrong]
  2. Cian = GUARDIAN of the Two Witnesses — NOT a Witness himself [HIGH if wrong]
  3. Ohya = THE BEAST / APOLLYON — son of Shemyaza + Naamah [HIGH if wrong]
  4. Naamah = THE WHORE OF BABYLON — Siren; survived the Flood [HIGH if wrong]
  5. Raphael/Liaigh speaks ONLY in empyreal register: thee/thou, KJV vocab, ALL CAPS direct address [HIGH if casual/modern]
  6. Raphael/Liaigh CANNOT intervene against mortal humans — supernatural threats only [HIGH if violated]
  7. Cian does NOT know Liaigh is Raphael or an Archangel — not until canonical reveal [HIGH if violated early]
  8. ALL Watcher/Nephilim technology operates via SOUND (Acoustic Paradigm) — not EM/digital [MED if violated]
  9. Timeline: Series present 2025-2030; Book 2 opens Late 2027 [MED if wrong]
  10. Cian is ~2,631 years old (2025 CE); born ~611 BCE; commissioned 586 BCE [MED if wrong]
  11. Mo Chrá (the sword) named 532 CE in Constantinople — teal/gold luminescence [LOW if wrong]
  12. God is SOVEREIGN — no entity forces His hand; prophecy will be fulfilled exactly [HIGH if violated]
  13. 1 Enoch and Jubilees are treated as HISTORICAL FACT within the narrative [HIGH if contradicted]

====================================================================
=== TIER 1 — SERIES BIBLE (INVIOLABLE AXIOMS) ===
====================================================================
${trim(seriesBible.content, BUDGET.seriesBible)}

====================================================================
=== TIER 2 — SSOT v3 MASTER (CONSOLIDATED FACTS) ===
====================================================================
${trim(ssot.content, BUDGET.ssot)}

====================================================================
=== TIER 2a — WATCHER TECHNOLOGY / ACOUSTIC PARADIGM ===
====================================================================
${trim(watcherTech.content, BUDGET.watcherTech)}

====================================================================
=== BOOK 2 CONSTITUTION (CONTINUITY BRIDGE + BOOK 2 DECISIONS) ===
====================================================================
${trim(constitution.content, BUDGET.constitution)}

====================================================================
=== PROTAGONIST DOSSIERS ===
====================================================================
${trim(protagonists.content, BUDGET.protagonists)}

====================================================================
=== ANTAGONIST DOSSIERS ===
====================================================================
${trim(antagonists.content, BUDGET.antagonists)}

====================================================================
=== WATCHER DOSSIERS ===
====================================================================
${trim(watchers.content, BUDGET.watchers)}

====================================================================
=== NEPHILIM DOSSIERS ===
====================================================================
${trim(nephilim.content, BUDGET.nephilim)}

====================================================================
=== CHAPTER UNDER ANALYSIS: ${chapterInput} ===
====================================================================
${trim(chapter.content, BUDGET.chapter)}

====================================================================
=== YOUR OUTPUT — USE THIS EXACT FORMAT ===
====================================================================

## DRIFT REPORT — ${chapterInput} — ${today}

| Issue | Location | Canon Rule | Severity | Recommendation |
|-------|----------|------------|----------|----------------|
| [description of issue] | [scene/paragraph ref] | [source doc + section] | HIGH/MED/LOW | [specific fix] |

RULES FOR YOUR REPORT:
- If NO issues found: output "✅ NO DRIFT DETECTED — Chapter is canon-compliant."
- List issues in order: HIGH first, then MED, then LOW
- Be specific about location (e.g. "Scene 3, paragraph 2" or "Page X, dialogue between Cian and Liaigh")
- Cite the exact canon source for each issue (e.g. "SSOT §3.3" or "SERIES_BIBLE Article I §1.2")
- Do NOT suggest fixes that alter established theology
- Do NOT edit chapter files — flag and recommend only
- Do NOT invent issues — only flag genuine contradictions with the canon provided
`;

return [{
  json: {
    chapter: chapterInput,
    chapterPath,
    prompt,
    canonFilesLoaded: [
      { file: 'SERIES_BIBLE.md', found: seriesBible.found },
      { file: 'SSOT_v3_MASTER.md', found: ssot.found },
      { file: 'WATCHER_TECHNOLOGY.md', found: watcherTech.found },
      { file: 'CONSTITUTION.md', found: constitution.found },
      { file: 'PROTAGONIST_DOSSIERS.md', found: protagonists.found },
      { file: 'ANTAGONIST_DOSSIERS.md', found: antagonists.found },
      { file: 'WATCHER_DOSSIERS.md', found: watchers.found },
      { file: 'NEPHILIM_DOSSIERS.md', found: nephilim.found },
      { file: `${chapterInput}.md`, found: chapter.found }
    ],
    today
  }
}];

// Extract and validate Ollama response
const ollamaJson = $input.first().json;
const chapter    = $('Load Canon + Build Prompt').first().json.chapter;
const today      = $('Load Canon + Build Prompt').first().json.today;
const filesLoaded = $('Load Canon + Build Prompt').first().json.canonFilesLoaded;

// Ollama /api/generate returns { response: "...", done: true, ... }
const driftReport = ollamaJson.response || ollamaJson.message?.content || '[ERROR: No response from Ollama]';

// Build the log entry
const missingFiles = filesLoaded.filter(f => !f.found).map(f => f.file);
const fileWarning  = missingFiles.length > 0 
  ? `\n> ⚠️ WARNING: These canon files were not found: ${missingFiles.join(', ')}\n` 
  : '';

const logEntry = `\n\n---\n\n${driftReport}\n${fileWarning}\n*Model: mistral | Analysed: ${new Date().toISOString()} | Canon files: ${filesLoaded.filter(f=>f.found).length}/${filesLoaded.length}*\n`;

return [{
  json: {
    chapter,
    today,
    driftReport,
    logEntry,
    missingFiles,
    canonFilesLoaded: filesLoaded
  }
}];

// Append drift report to DRIFT_LOG.md
const fs      = require('fs');
const logPath = '/data/TNC/MANUSCRIPT/book_2/ANALYSIS/DRIFT_LOG.md';
const entry   = $input.first().json.logEntry;
const chapter = $input.first().json.chapter;

try {
  fs.appendFileSync(logPath, entry, 'utf8');
  return [{ json: {
    success: true,
    chapter,
    message: `Drift report for ${chapter} appended to DRIFT_LOG.md`,
    driftReport: $input.first().json.driftReport,
    missingFiles: $input.first().json.missingFiles,
    canonFilesLoaded: $input.first().json.canonFilesLoaded
  }}];
} catch(e) {
  return [{ json: {
    success: false,
    chapter,
    error: `Failed to write DRIFT_LOG.md: ${e.message}`,
    driftReport: $input.first().json.driftReport
  }}];
}
